// Omise webhook payload: { key: 'charge.complete'|'charge.create'|..., data: { id, status, paid_at, failure_code, ... } }
const body = $json.body || {};
const data = body.data || {};
const s = String(data.status || '').toLowerCase();

// ไม่ default เป็น pending — เพื่อไม่ override DB เมื่อ event เป็น 'charge.create' ที่ยัง pending
let status = '';
if (s === 'successful' || data.paid === true) status = 'paid';
else if (s === 'failed' || data.failure_code) status = 'failed';
else if (s === 'expired' || s === 'reversed') status = 'expired';
// ถ้า status ไม่ใช่ final → ส่ง '' ไป SQL จะ keep ค่าเดิม

return [{
  json: {
    charge_id: data.id || '',
    status,
    paid_at: data.paid_at || (status === 'paid' ? new Date().toISOString() : ''),
    raw: JSON.stringify(body).replace(/'/g, "''")
  }
}];
